"""Tests pour le module d'analyse."""
import pytest from optigestion.modules.analysis_module import ( calculer_seuil_rentabilite, simuler_scenario, analyser_sensibilite )
class TestCalculerSeuilRentabilite: """Tests pour la fonction calculer_seuil_rentabilite."""
def test_seuil_rentabilite_basique(self): """Test du calcul de base.""" resultat = calculer_seuil_rentabilite( couts_fixes_totaux=10000.0, prix_vente_unitaire=100.0, cout_variable_unitaire=60.0 ) assert resultat == 250.0 # 10000 / (100 - 60) = 250
def test_seuil_rentabilite_marge_nulle(self): """Test avec une marge de contribution nulle.""" resultat = calculer_seuil_rentabilite( couts_fixes_totaux=10000.0, prix_vente_unitaire=60.0, cout_variable_unitaire=60.0 ) assert resultat == float('inf')
def test_seuil_rentabilite_marge_negative(self): """Test avec une marge de contribution négative.""" resultat = calculer_seuil_rentabilite( couts_fixes_totaux=10000.0, prix_vente_unitaire=50.0, cout_variable_unitaire=60.0 ) assert resultat == float('inf')
